const users = $('Fetch User Metrics').first().json;
const revenue = $('Fetch Revenue Metrics').first().json;
const perf = $('Fetch Performance Card').first().json;
const referrals = $('Fetch Referral Leaderboard').first().json;

const prompt = `Analyze the following weekly business metrics for BTC Seer and provide:
1. Key highlights (what went well)
2. Concerns (what needs attention)
3. Trends (compare to implied previous performance)
4. Top 3 actionable recommendations for next week

Be concise and direct. This is an internal owner report, not public-facing.

User Metrics: ${JSON.stringify(users)}

Revenue Metrics (7 days): ${JSON.stringify(revenue)}

Performance Card (7 days): ${JSON.stringify(perf)}

Referral Leaderboard: ${JSON.stringify(referrals)}

Format as plain text with sections. Max 800 words.`;

return [{ json: { prompt, users, revenue, perf, referrals } }];

const response = $input.first().json;
let analysis = '';

if (response.content && response.content.length > 0) {
  analysis = response.content[0].text;
} else {
  analysis = 'Claude analysis unavailable this week.';
}

return [{ json: { analysis } }];

const users = $('Build Claude Prompt').first().json.users;
const revenue = $('Build Claude Prompt').first().json.revenue;
const perf = $('Build Claude Prompt').first().json.perf;
const referrals = $('Build Claude Prompt').first().json.referrals;
const analysis = $('Extract Analysis').first().json.analysis;

const weekEnd = new Date().toISOString().split('T')[0];
const weekStart = new Date(Date.now() - 7 * 86400000).toISOString().split('T')[0];

const totalUsers = users.total_users ?? users.totalUsers ?? 0;
const newUsers = users.new_users_week ?? users.newUsersWeek ?? users.new_users_today ?? 0;
const premiumUsers = users.premium_users ?? users.premiumUsers ?? 0;
const trialUsers = users.trial_users ?? users.trialUsers ?? 0;
const churnRate = users.churn_rate ?? users.churnRate ?? 'N/A';

const stars = revenue.total_stars ?? revenue.totalStars ?? 0;
const usd = revenue.total_usd ?? revenue.totalUsd ?? (stars * 0.02).toFixed(2);
const conversions = revenue.trial_conversions ?? revenue.trialConversions ?? 0;
const arpu = revenue.arpu ?? (premiumUsers > 0 ? (stars / premiumUsers).toFixed(1) : '0');

const predMade = perf.predictions_made ?? perf.predictionsMade ?? 0;
const predCorrect = perf.predictions_correct ?? perf.predictionsCorrect ?? 0;
const accuracy = perf.accuracy ?? (predMade > 0 ? ((predCorrect / predMade) * 100).toFixed(1) : '0.0');
const signals = perf.trading_signals ?? perf.tradingSignals ?? 0;
const profitable = perf.profitable_signals ?? perf.profitableSignals ?? 0;

const topReferrers = Array.isArray(referrals.leaderboard ?? referrals) ? (referrals.leaderboard ?? referrals).slice(0, 5) : [];
const referralList = topReferrers.length > 0
  ? topReferrers.map((r, i) => `  ${i + 1}. ${r.username ?? r.name ?? 'User'} \u2014 ${r.referrals ?? r.count ?? 0} referrals`).join('\n')
  : '  No referral data';

const report = `\u{1F4CA} <b>Weekly Business Report</b>\n${weekStart} \u2192 ${weekEnd}\n\n` +
  `<b>\u{1F465} USERS</b>\n+${newUsers} new | ${totalUsers} total | ${premiumUsers} premium | ${trialUsers} trial | churn: ${churnRate}\n\n` +
  `<b>\u{1F4B0} REVENUE</b>\n${stars} Stars (~$${usd}) | ${conversions} conversions | ARPU: ${arpu}\n\n` +
  `<b>\u{1F3AF} PREDICTIONS</b>\n${predMade} made | ${predCorrect} correct (${accuracy}%) | ${signals} signals | ${profitable} profitable\n\n` +
  `<b>\u{1F517} TOP REFERRERS</b>\n${referralList}\n\n` +
  `<b>\u{1F916} AI ANALYSIS</b>\n${analysis}`;

const discordSummary = `**Weekly Business Report** (${weekStart} \u2192 ${weekEnd})\n\n` +
  `**Users:** +${newUsers} new | ${totalUsers} total | ${premiumUsers} premium\n` +
  `**Revenue:** ${stars} Stars (~$${usd}) | ${conversions} conversions\n` +
  `**Predictions:** ${predMade} made | ${accuracy}% accuracy\n` +
  `**Signals:** ${signals} total | ${profitable} profitable\n\n` +
  `Full report sent to Telegram.`;

return [{ json: { report, discordSummary } }];

const tgResult = $('Send to Admin Telegram').first().json;
const discordResult = $('Send to Discord').first().json;
const now = new Date().toISOString();

const tgSuccess = tgResult.ok === true;
console.log(`[${now}] Weekly Business Report — TG: ${tgSuccess ? 'OK' : 'FAIL'} | Discord: sent`);

return [{ json: { logged: true, telegram: tgSuccess, timestamp: now } }];
